module pcie_request_decoder(  
    input [3:0] request_type,  
    output reg [1:0] obf_command  
);  
    always @(*) begin  
        case(request_type)  
            4'b0000: obf_command = 2'b00;  
            4'b0001: obf_command = 2'b01;  
            4'b0010: obf_command = 2'b10;  
            4'b0011: obf_command = 2'b11;  
            default: obf_command = 2'b00;  
        endcase  
    end  
endmodule
